function setupForm(ctx) {
  const { doc, call, createToast, $dialog } = ctx;

  console.log('[JustCall] Setting up form script for ticket:', doc.name);

  // Helper function to normalize phone number
  function normalizePhoneNumber(phone) {
    if (!phone) return '';
    return phone.toString().trim();
  }

  // Helper function to get contact phone number
  async function getContactPhone() {
    if (doc.contact) {
      const phone = doc.contact.phone || doc.contact.mobile_no;
      if (phone) {
        return {
          phone: normalizePhoneNumber(phone),
          name: doc.contact.name || doc.contact.full_name || ''
        };
      }
    }

    try {
      const result = await call('justcall_integration.api.get_ticket_contact_phone', {
        ticket_id: doc.name
      });
      return {
        phone: normalizePhoneNumber(result?.phone),
        name: result?.contact_name || ''
      };
    } catch (e) {
      console.error('[JustCall] Error fetching contact phone:', e);
      return { phone: null, name: '' };
    }
  }

  // Open JustCall dialer in new tab with metadata
  async function openJustCallDialer() {
    const contactInfo = await getContactPhone();

    if (!contactInfo.phone) {
      createToast({
        title: 'No phone number',
        message: 'This ticket does not have a contact with a phone number.',
        appearance: 'warning',
      });
      return;
    }

    const metadata = {
      ticket_id: doc.name,
      contact: contactInfo.name || doc.contact?.name || '',
      subject: doc.subject || '',
    };

    const baseUrl = 'https://app.justcall.io/dialer';
    const params = new URLSearchParams();
    params.append('numbers', contactInfo.phone);
    params.append('medium', 'custom');
    params.append('metadata', JSON.stringify(metadata));
    params.append('metadata_type', 'json');

    const dialerUrl = `${baseUrl}?${params.toString()}`;
    window.open(dialerUrl, '_blank');
  }

  // Open JustCall dialer without metadata (standby mode)
  function openJustCallStandby() {
    window.open('https://app.justcall.io/dialer', '_blank');
    createToast({
      title: 'JustCall Standby',
      message: 'JustCall dialer opened. You are now on standby for incoming calls.',
      appearance: 'info',
    });
  }

  // Open modal to link calls to this ticket
  async function openLinkCallsModal() {
    console.log('[JustCall] Opening link calls modal...');

    try {
      const calls = await call('justcall_integration.api.get_calls_without_ticket');
      console.log('[JustCall] Received calls:', calls);

      if (!calls || calls.length === 0) {
        createToast({
          title: 'No Unlinked Calls',
          message: 'There are no call logs waiting to be linked to this ticket.',
          appearance: 'info',
        });
        return;
      }

      // Track selected calls
      let selectedCalls = [];

      // Build table rows HTML
      let tableRowsHtml = calls.map((call) => {
        const typeColor = call.type === 'Incoming' ? '#28a745' : '#007bff';
        const hasRecording = call.recording_url && call.recording_url.length > 0;

        return `
          <tr style="border-bottom: 1px solid #f0f0f0;">
            <td style="padding: 10px; text-align: center;">
              <input type="checkbox" class="jc-call-checkbox" data-name="${call.name}" style="cursor: pointer;">
            </td>
            <td style="padding: 10px;">${call.from || '-'}</td>
            <td style="padding: 10px;">${call.to || '-'}</td>
            <td style="padding: 10px; color: ${typeColor}; font-weight: 500;">${call.type}</td>
            <td style="padding: 10px;">${call.status}</td>
            <td style="padding: 10px;">${call.duration_formatted || '0s'}</td>
            <td style="padding: 10px;">
              ${hasRecording ? `<a href="${call.recording_url}" target="_blank" style="color: #007bff; text-decoration: none;">▶ Play</a>` : '-'}
            </td>
          </tr>
        `;
      }).join('');

      // Use $dialog from ctx - it should work now
      const dialog = $dialog({
        title: `Link Call Log to Ticket ${doc.name}`,
        size: '3xl'
      });

      // Build content HTML
      const contentHtml = `
        <div id="jc-modal-content" style="padding: 20px;">
          <p style="margin-bottom: 15px; color: #666;">Found ${calls.length} call(s) without linked ticket. Select calls to link:</p>
          <div style="max-height: 400px; overflow-y: auto;">
            <table style="width: 100%; border-collapse: collapse; font-size: 13px;">
              <thead style="background: #f7f7f7; position: sticky; top: 0;">
                <tr>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5; width: 40px;">
                    <input type="checkbox" id="jc-select-all" style="cursor: pointer;">
                  </th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5;">From</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5;">To</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5;">Type</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5;">Status</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5;">Duration</th>
                  <th style="padding: 10px; text-align: left; border-bottom: 1px solid #e5e5e5;">Recording</th>
                </tr>
              </thead>
              <tbody>
                ${tableRowsHtml}
              </tbody>
            </table>
          </div>
          <div style="display: flex; justify-content: flex-end; padding-top: 20px; border-top: 1px solid #e5e5e5; margin-top: 20px;">
            <button id="jc-link-btn" style="background: #171717; color: white; border: none; padding: 10px 20px; border-radius: 6px; cursor: pointer; font-size: 14px; font-weight: 500;">
              Link to this ticket
            </button>
          </div>
        </div>
      `;

      // Set content - different methods depending on dialog structure
      if (dialog && dialog.el) {
        // Method 1: Direct element
        const contentEl = dialog.el.querySelector('.modal-body') || dialog.el.querySelector('[role="dialog"] > div');
        if (contentEl) {
          contentEl.innerHTML = contentHtml;
        }
      } else if (dialog && dialog.$el) {
        // Method 2: Vue $el
        const modalBody = dialog.$el.querySelector('.modal-body');
        if (modalBody) {
          modalBody.innerHTML = contentHtml;
        }
      } else {
        // Method 3: Create custom modal as fallback
        console.log('[JustCall] Using fallback custom modal');
        createCustomModal(contentHtml, selectedCalls, calls);
        return;
      }

      // Attach event listeners
      setTimeout(() => {
        attachEventListeners(dialog, selectedCalls);
      }, 100);

    } catch (e) {
      console.error('[JustCall] Error in openLinkCallsModal:', e);
      createToast({
        title: 'Error',
        message: 'Failed to open modal. Please try again.',
        appearance: 'error',
      });
    }
  }

  // Fallback: Create custom modal
  function createCustomModal(contentHtml, selectedCalls, calls) {
    // Remove existing modal if any
    const existingModal = document.getElementById('jc-custom-modal');
    if (existingModal) {
      existingModal.remove();
    }

    // Create modal overlay
    const overlay = document.createElement('div');
    overlay.id = 'jc-custom-modal';
    overlay.style.cssText = 'position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.5); z-index: 9999; display: flex; align-items: center; justify-content: center;';

    // Create modal content
    const modalContent = document.createElement('div');
    modalContent.style.cssText = 'background: white; border-radius: 8px; width: 90%; max-width: 1000px; max-height: 80vh; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.3);';

    // Header
    const header = document.createElement('div');
    header.style.cssText = 'padding: 20px; border-bottom: 1px solid #e5e5e5; display: flex; justify-content: space-between; align-items: center;';
    header.innerHTML = `
      <h3 style="margin: 0; font-size: 18px; font-weight: 600;">Link Call Log to Ticket ${doc.name}</h3>
      <button id="jc-close-modal" style="background: none; border: none; font-size: 24px; cursor: pointer; color: #666;">&times;</button>
    `;

    // Body with content
    const body = document.createElement('div');
    body.innerHTML = contentHtml;

    modalContent.appendChild(header);
    modalContent.appendChild(body);
    overlay.appendChild(modalContent);
    document.body.appendChild(overlay);

    // Close button
    document.getElementById('jc-close-modal').addEventListener('click', () => {
      overlay.remove();
    });

    // Close on overlay click
    overlay.addEventListener('click', (e) => {
      if (e.target === overlay) {
        overlay.remove();
      }
    });

    // Attach checkbox listeners
    attachEventListenersToElement(body, selectedCalls);

    // Link button handler
    const linkBtn = document.getElementById('jc-link-btn');
    if (linkBtn) {
      linkBtn.addEventListener('click', async () => {
        if (selectedCalls.length === 0) {
          createToast({
            title: 'No Calls Selected',
            message: 'Please select at least one call to link.',
            appearance: 'warning',
          });
          return;
        }

        linkBtn.disabled = true;
        linkBtn.textContent = 'Linking...';

        try {
          const result = await call('justcall_integration.api.link_calls_to_ticket', {
            ticket_id: doc.name,
            call_log_names: selectedCalls
          });

          if (result.success) {
            createToast({
              title: 'Success',
              message: `Linked ${result.linked_count} call(s) to this ticket.`,
              appearance: 'success',
            });
            overlay.remove();
          } else {
            createToast({
              title: 'Error',
              message: result.message || 'Failed to link calls.',
              appearance: 'error',
            });
            linkBtn.disabled = false;
            linkBtn.textContent = 'Link to this ticket';
          }
        } catch (err) {
          console.error('[JustCall] Link error:', err);
          createToast({
            title: 'Error',
            message: 'Failed to link calls. Please try again.',
            appearance: 'error',
          });
          linkBtn.disabled = false;
          linkBtn.textContent = 'Link to this ticket';
        }
      });
    }
  }

  // Attach event listeners to dialog
  function attachEventListeners(dialog, selectedCalls) {
    console.log('[JustCall] Attaching event listeners...');

    let container = null;
    if (dialog && dialog.el) {
      container = dialog.el;
    } else if (dialog && dialog.$el) {
      container = dialog.$el;
    }

    if (!container) {
      console.error('[JustCall] Dialog container not found');
      return;
    }

    attachEventListenersToElement(container, selectedCalls);

    // Link button
    const linkBtn = container.querySelector('#jc-link-btn');
    if (linkBtn) {
      linkBtn.addEventListener('click', async () => {
        if (selectedCalls.length === 0) {
          createToast({
            title: 'No Calls Selected',
            message: 'Please select at least one call to link.',
            appearance: 'warning',
          });
          return;
        }

        linkBtn.disabled = true;
        linkBtn.textContent = 'Linking...';

        try {
          const result = await call('justcall_integration.api.link_calls_to_ticket', {
            ticket_id: doc.name,
            call_log_names: selectedCalls
          });

          if (result.success) {
            createToast({
              title: 'Success',
              message: `Linked ${result.linked_count} call(s) to this ticket.`,
              appearance: 'success',
            });
            if (dialog.close) dialog.close();
            if (dialog.hide) dialog.hide();
          } else {
            createToast({
              title: 'Error',
              message: result.message || 'Failed to link calls.',
              appearance: 'error',
            });
            linkBtn.disabled = false;
            linkBtn.textContent = 'Link to this ticket';
          }
        } catch (err) {
          console.error('[JustCall] Link error:', err);
          createToast({
            title: 'Error',
            message: 'Failed to link calls. Please try again.',
            appearance: 'error',
          });
          linkBtn.disabled = false;
          linkBtn.textContent = 'Link to this ticket';
        }
      });
    }
  }

  // Attach checkbox listeners to element
  function attachEventListenersToElement(element, selectedCalls) {
    // Select all
    const selectAll = element.querySelector('#jc-select-all');
    if (selectAll) {
      selectAll.addEventListener('change', (e) => {
        console.log('[JustCall] Select all:', e.target.checked);
        const checkboxes = element.querySelectorAll('.jc-call-checkbox');
        selectedCalls.length = 0;
        checkboxes.forEach(cb => {
          cb.checked = e.target.checked;
          if (e.target.checked) {
            selectedCalls.push(cb.dataset.name);
          }
        });
        console.log('[JustCall] Selected:', selectedCalls);
      });
    }

    // Individual checkboxes
    const checkboxes = element.querySelectorAll('.jc-call-checkbox');
    console.log('[JustCall] Found checkboxes:', checkboxes.length);
    checkboxes.forEach(cb => {
      cb.addEventListener('change', (e) => {
        const name = e.target.dataset.name;
        if (e.target.checked) {
          if (!selectedCalls.includes(name)) {
            selectedCalls.push(name);
          }
        } else {
          const idx = selectedCalls.indexOf(name);
          if (idx > -1) selectedCalls.splice(idx, 1);
        }
        console.log('[JustCall] Selected:', selectedCalls);
      });
    });
  }

  // Return actions
  return {
    actions: [
      {
        label: 'Call via JustCall',
        onClick: openJustCallDialer,
        variant: 'solid',
        theme: 'blue',
      },
      {
        label: 'Standby via JustCall',
        onClick: openJustCallStandby,
        variant: 'outline',
        theme: 'gray',
      },
      {
        group: 'JustCall',
        hideLabel: true,
        items: [
          {
            label: 'Link Call Log to this Ticket',
            onClick: openLinkCallsModal,
          },
        ],
      },
    ]
  };
}
